class Solution:
    def isFascinating(self, n: int) -> bool:
        s = str(n) + str(2 * n) + str(3 * n)
        if len(s) != 9:
            return False
        counts = [0] * 10
        for ch in s:
            counts[int(ch)] += 1
        if counts[0] != 0:
            return False
        for d in range(1, 10):
            if counts[d] != 1:
                return False
        return True

